script:
const $r = root_element;
const $ = (sel) => $r.querySelector(sel);
const escape = (s) => frappe.utils.escape_html(s == null ? "" : String(s));

function bindEvents() {
  const zone = $("#ai-drop-zone");
  const input = $("#ai-file-input");
  zone.addEventListener("dragover", (e) => { e.preventDefault(); zone.classList.add("drag-over"); });
  zone.addEventListener("dragleave", () => zone.classList.remove("drag-over"));
  zone.addEventListener("drop", (e) => {
    e.preventDefault();
    zone.classList.remove("drag-over");
    if (e.dataTransfer.files.length) uploadFiles(e.dataTransfer.files);
  });
  zone.addEventListener("click", () => input.click());
  input.addEventListener("change", () => { if (input.files.length) uploadFiles(input.files); });
}

function uploadFiles(files) {
  const prog = $("#ai-progress");
  prog.style.display = "block";
  prog.className = "ai-progress";
  prog.textContent = `Uploading ${files.length} file(s)…`;

  Promise.all(Array.from(files).map(uploadOne))
    .then((results) => {
      const flat = results.flat();
      prog.className = "ai-progress success";
      prog.innerHTML = `✓ ${flat.length} import job(s) queued — <strong>${flat.map(escape).join(", ")}</strong>`;
      refreshJobs();
      $("#ai-file-input").value = "";
    })
    .catch((err) => {
      prog.className = "ai-progress error";
      prog.textContent = "Upload failed: " + (err.message || err);
    });
}

function uploadOne(file) {
  const fd = new FormData();
  fd.append("file", file);
  return fetch("/api/method/erpnext_ai_importer.api.upload.upload_invoice", {
    method: "POST",
    headers: { "X-Frappe-CSRF-Token": frappe.csrf_token },
    body: fd,
  }).then(r => r.json()).then(data => {
    if (data.exc) throw new Error(data._server_messages || data.exc);
    return data.message || [];
  });
}

function refreshJobs() {
  return frappe.call({
    method: "frappe.client.get_list",
    args: {
      doctype: "AI Document Import",
      fields: ["name","company","party","extracted_supplier_name","total","status","purchase_invoice","source_file","creation","supplier_match_score"],
      order_by: "creation desc",
      limit: 50,
    },
  }).then(r => renderJobs(r.message || []));
}

function renderJobs(rows) {
  const count = $("#ai-job-count");
  const list = $("#ai-job-list");
  if (!rows.length) {
    count.textContent = "";
    list.innerHTML = `<div class="ai-empty">No imports yet — drop a file above to get started.</div>`;
    return;
  }
  count.textContent = `${rows.length} records`;
  const tbody = rows.map(r => `<tr>
    <td>${fileIcon(r.source_file)} ${escape(fileName(r))}</td>
    <td>${escape(r.company || "—")}</td>
    <td>${partyCell(r)}</td>
    <td>${r.total ? frappe.format(r.total, {fieldtype:"Currency"}) : "—"}</td>
    <td>${statusBadge(r.status)}</td>
    <td>${actionCell(r)}</td>
  </tr>`).join("");
  list.innerHTML = `<table class="ai-table">
    <thead><tr><th>File</th><th>Company</th><th>Supplier</th><th>Total</th><th>Status</th><th></th></tr></thead>
    <tbody>${tbody}</tbody>
  </table>`;
}

function fileName(r) { return r.source_file ? r.source_file.split("/").pop() : r.name; }
function fileIcon(sf) {
  if (!sf) return "📄";
  const ext = sf.split(".").pop().toLowerCase();
  if (ext === "zip") return "📦";
  if (["xlsx","xls","csv"].includes(ext)) return "📊";
  return "📄";
}
function partyCell(row) {
  if (!row.party) {
    if (row.extracted_supplier_name) return `<span style="color:#dc2626">⚠ No match for "${escape(row.extracted_supplier_name)}"</span>`;
    return "—";
  }
  const score = row.supplier_match_score || 0;
  const color = score >= 85 ? "#16a34a" : score >= 60 ? "#d97706" : "#dc2626";
  return `<span style="color:${color}">${escape(row.party)}</span> <span style="font-size:10px;color:#9ca3af;margin-left:4px">${score}%</span>`;
}
function statusBadge(status) {
  const map = {
    "Draft":              { bg:"#f1f5f9", color:"#475569" },
    "Extracting":         { bg:"#dbeafe", color:"#1e40af" },
    "Pending Validation": { bg:"#fef9c3", color:"#92400e" },
    "Submitted":          { bg:"#dcfce7", color:"#166534" },
    "Failed":             { bg:"#fee2e2", color:"#991b1b" },
  };
  const s = map[status] || { bg:"#f1f5f9", color:"#374151" };
  return `<span class="ai-badge" style="background:${s.bg};color:${s.color}">${escape(status||"")}</span>`;
}
function actionCell(row) {
  if (row.status === "Submitted" && row.purchase_invoice) {
    const url = frappe.utils.get_form_link("Purchase Invoice", row.purchase_invoice);
    return `<a class="ai-link" href="${url}">${escape(row.purchase_invoice)}</a>`;
  }
  const url = "/app/ai-invoice-validate/" + encodeURIComponent(row.name);
  if (row.status === "Pending Validation" || row.status === "Failed")
    return `<a class="ai-link" href="${url}">${row.status === "Failed" ? "View →" : "Validate →"}</a>`;
  if (row.status === "Extracting")
    return `<span style="color:#9ca3af;font-size:11px">Processing…</span>`;
  return `<a class="ai-link" href="${url}">View →</a>`;
}

bindEvents();
refreshJobs();
setInterval(refreshJobs, 10000);

style:
.ai-root { max-width:960px; margin:0 auto; padding:0 2px; }
.ai-drop-zone { border:2px dashed #cbd5e1; border-radius:8px; padding:48px 32px; text-align:center; background:#f8fafc; cursor:pointer; transition:background 0.15s,border-color 0.15s; margin-bottom:14px; }
.ai-drop-zone:hover, .ai-drop-zone.drag-over { background:#eff6ff; border-color:#2563eb; }
.ai-dz-icon { font-size:2.2rem; color:#9ca3af; margin-bottom:6px; }
.ai-dz-title { font-size:14px; font-weight:600; color:#374151; }
.ai-dz-hint { font-size:12px; color:#9ca3af; margin-top:4px; }
#ai-file-input { display:none; }
.ai-progress { margin-bottom:12px; padding:10px 14px; border-radius:6px; font-size:12px; background:#eff6ff; border:1px solid #bfdbfe; color:#1d4ed8; }
.ai-progress.success { background:#f0fdf4; border-color:#bbf7d0; color:#15803d; }
.ai-progress.error { background:#fef2f2; border-color:#fecaca; color:#b91c1c; }
.ai-card { background:#fff; border:1px solid #e2e8f0; border-radius:8px; overflow:hidden; }
.ai-card-head { display:flex; justify-content:space-between; align-items:center; padding:12px 16px; border-bottom:1px solid #e2e8f0; }
.ai-card-title { font-size:13px; font-weight:600; color:#374151; }
.ai-card-sub { font-size:11px; color:#9ca3af; }
.ai-empty { padding:32px; text-align:center; color:#9ca3af; font-size:13px; }
.ai-table { width:100%; border-collapse:collapse; font-size:12px; }
.ai-table th { color:#9ca3af; font-size:10px; text-transform:uppercase; letter-spacing:0.04em; font-weight:600; padding:8px 12px; border-bottom:1px solid #e2e8f0; text-align:left; }
.ai-table td { padding:8px 12px; border-bottom:1px solid #f3f4f6; color:#374151; vertical-align:middle; }
.ai-table tbody tr:last-child td { border-bottom:none; }
.ai-badge { display:inline-block; padding:2px 8px; border-radius:4px; font-size:10px; font-weight:600; white-space:nowrap; }
.ai-link { color:#2563eb; text-decoration:none; font-size:11px; }
.ai-link:hover { text-decoration:underline; }
